// ─── Helper Functions ──────────────────────────────────────────────────────────

/**
 * Get an industry by its slug
 */
export function getIndustryBySlug(slug) {
  return industries.find(i => i.slug === slug) || null;
}

/**
 * Get a service by industry slug + service slug
 */
export function getServiceBySlug(industrySlug, serviceSlug) {
  const industry = getIndustryBySlug(industrySlug);
  if (!industry) return null;
  return industry.services.find(s => s.slug === serviceSlug) || null;
}

/**
 * Get all static paths for [industry] pages
 */
export function getAllIndustryPaths() {
  return industries.map(i => ({ industry: i.slug }));
}

/**
 * Get all static paths for [industry]/[service] pages
 */
export function getAllServicePaths() {
  return industries.flatMap(i =>
    i.services.map(s => ({ industry: i.slug, service: s.slug }))
  );
}
